class Solution {
    public char repeatedCharacter(String s) {
        int countMap[] = new int[26];
        for (char c : s.toCharArray()) {
            countMap[c - 'a']++;
        }
        for (int i = 0; i < s.length(); i++) {
            if (countMap[s.charAt(i) - 'a'] > 1) {
                return s.charAt(i);
            }
        }
        return '\0';
    }
}
```

